    // Configuration key constants
    private static final String ENV_ENDPOINT = "OSS_ENDPOINT";
    private static final String ENV_ACCESS_KEY_ID = "OSS_ACCESS_KEY_ID";
    private static final String ENV_ACCESS_KEY_SECRET = "OSS_ACCESS_KEY_SECRET";
    private static final String ENV_BUCKET_NAME = "OSS_BUCKET_NAME";

    // Instance fields
    private final String endpoint;
    private final String bucketName;
    private final OSS ossClient;

    /**
     * Default constructor
     * Initializes OSS client using configuration from environment variables or system properties
     * 
     * @throws IllegalStateException if required configuration is missing
     */
    public OSSService() {
        this.endpoint = getConfig(ENV_ENDPOINT);
        String accessKeyId = getConfig(ENV_ACCESS_KEY_ID);
        String accessKeySecret = getConfig(ENV_ACCESS_KEY_SECRET);
        this.bucketName = getConfig(ENV_BUCKET_NAME);

        // Initialize OSS client (thread-safe)
        this.ossClient = new OSSClientBuilder().build(endpoint, accessKeyId, accessKeySecret);
    }

    /**
     * Get configuration value from environment variable or system property
     * Environment variables take precedence over system properties
     * 
     * @param key configuration key name
     * @return configuration value
     * @throws IllegalStateException if configuration is not found
     */
    private String getConfig(String key) {
        // First try environment variable
        String value = System.getenv(key);
        if (value != null && !value.trim().isEmpty()) {
            return value.trim();
        }

        // Fallback to system property
        value = System.getProperty(key);
        if (value != null && !value.trim().isEmpty()) {
            return value.trim();
        }

        throw new IllegalStateException("Configuration not found: " + key + 
            ". Please set environment variable or system property.");
    }

    /**
     * Upload file to OSS
     * 
     * @param objectName The object name (path/filename) in OSS, e.g., "images/photo.jpg"
     * @param data The file data as byte array
     * @return The complete URL to access the uploaded resource
     * @throws IllegalArgumentException if parameters are invalid
     * @throws RuntimeException if upload fails
     */
    public String uploadFile(String objectName, byte[] data) {
        // Parameter validation
        if (objectName == null || objectName.trim().isEmpty()) {
            throw new IllegalArgumentException("Object name cannot be null or empty");
        }
        if (data == null || data.length == 0) {
            throw new IllegalArgumentException("Data cannot be null or empty");
        }

        // Normalize object name (remove leading slash if present)
        String normalizedObjectName = objectName.startsWith("/") 
            ? objectName.substring(1) : objectName;

        try (InputStream inputStream = new ByteArrayInputStream(data)) {
            // Upload to OSS
            PutObjectResult result = ossClient.putObject(bucketName, normalizedObjectName, inputStream);

            // Build and return the access URL
            // Remove protocol prefix from endpoint if present
            String cleanEndpoint = endpoint.replaceFirst("^https?://", "");
            return String.format("https://%s.%s/%s", bucketName, cleanEndpoint, normalizedObjectName);

        } catch (Exception e) {
            throw new RuntimeException("Failed to upload file to OSS: " + e.getMessage(), e);
        }
    }

    /**
     * Shutdown the OSS client and release resources
     * Should be called when the service is no longer needed
     */
    public void shutdown() {
        if (ossClient != null) {
            ossClient.shutdown();
        }
    }
}
